at::Tensor matmul_npu_impl(const at::Tensor& A, const at::Tensor& B) {
    at::Tensor result = at::empty({A.size(0), B.size(1)}, A.options());
    EXEC_NPU_CMD(aclnnMatmulWithSmallKDimensionCustom, A, B, result);
    return result;
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
    m.impl("matmul_with_small_k_dimension_custom", &matmul_npu_impl);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("matmul_with_small_k_dimension_custom", &matmul_npu_impl, "MatMul with small K dimension (MatmulWithSmallKDimensionCustom on NPU)");
}
